#include<bits/stdc++.h>
using namespace std;
vector<int> a[100010];
int main(void){
    int n,q;
    cin>>n>>q;
    while(q--){
        int opr,x,y,z;
        cin>>opr;
        if(opr==1){
            cin>>x>>y>>z;
            if(a[x].size()<y+1)a[x].resize(y+1);
            a[x][y]=z;
        }else{
            cin>>x>>y;
            cout<<a[x][y]<<endl;
        }
    }
    return false;
}
